import React, { useState, useRef } from 'react';
import './App.css';
import Captcha from './Captcha';

function App() {
  const [institutionCaptcha, setInstitutionCaptcha] = useState('');
  const [studentCaptcha, setStudentCaptcha] = useState('');

  const [institutionInput, setInstitutionInput] = useState('');
  const [studentInput, setStudentInput] = useState('');

  const studentCaptchaRef = useRef(null);

  const handleRefreshCaptcha = () => {
    if (studentCaptchaRef.current) {
      studentCaptchaRef.current.refreshCaptcha();
    }
  };

  return (
    <div className="app-container">
      {/* Header Section */}
      <header className="app-header">
        <div className="logo-container left-logo">
          {/* Using provided AAMEC logo */}
          <img src="https://i.ibb.co/V1YgqZq/AAMEC.jpg" alt="AAMEC Logo" className="au-logo" />
        </div>
        <div className="header-titles">
          <h1>ANJALAI AMMAL MAHALINGAM ENGINEERING COLLEGE</h1>
        </div>
        <div className="logo-container right-logo">
          <img src="https://i.ibb.co/V1YgqZq/AAMEC.jpg" alt="AAMEC Logo" className="au-logo" style={{ borderRadius: '50%' }} />
        </div>
      </header>

      {/* Main Content Area */}
      <main className="main-content">

        {/* Welcome Banner */}
        <div className="welcome-banner">
          <h2>Welcome to ANJALAI AMMAL MAHALINGAM ENGINEERING COLLEGE</h2>
        </div>

        {/* 3 Column Layout below banner */}
        <div className="panels-container">

          {/* Student Login Panel */}
          <div className="login-panel">
            <h3 className="panel-title">Student Portal Login</h3>
            <form className="login-form student-form">
              <div className="form-group">
                <label>Register Number</label>
                <input type="text" />
              </div>
              <div className="form-group dob-group">
                <div className="dob-labels">
                  <label>Date of Birth</label>
                  <span className="date-format">[DD-MM-YYYY]</span>
                </div>
                <input type="text" />
              </div>
              <div className="form-group captcha-input-group">
                <label>Enter the Captcha <span className="play-btn">▶ Play</span></label>
                <input 
                  type="text" 
                  className="captcha-input"
                  value={studentInput}
                  onChange={(e) => setStudentInput(e.target.value)}
                />
              </div>

              <div className="captcha-wrapper">
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                  <Captcha ref={studentCaptchaRef} onChange={setStudentCaptcha} />
                  <button type="button" onClick={handleRefreshCaptcha} className="refresh-captcha-btn" title="Refresh Captcha">
                    ↻
                  </button>
                </div>
              </div>

              <div className="form-actions">
                <button type="button" className="login-btn">Secure Login</button>
              </div>
            </form>
          </div>



        </div>
      </main>
    </div>
  );
}

export default App;
